     1→import { spawn } from "node:child_process";
     2→import { randomBytes } from "node:crypto";
     3→import {
     4→	createServer,
     5→	type IncomingMessage,
     6→	type ServerResponse,
     7→} from "node:http";
     8→import type { AddressInfo } from "node:net";
     9→import * as p from "@clack/prompts";
    10→import { buildCommand } from "@stricli/core";
    11→import { loadCredentials, saveCredentials } from "../lib/credentials.js";
    12→
    13→const DEFAULT_API_BASE = "https://app.rudel.ai";
    14→const DEFAULT_WEB_URL = "https://app.rudel.ai";
    15→const CALLBACK_TIMEOUT_MS = 120_000;
    16→
    17→async function runLogin(flags: {
    18→	apiBase: string;
    19→	webUrl: string;
    20→	noBrowser: boolean;
    21→}): Promise<void> {
    22→	p.intro("rudel login");
    23→
    24→	const existing = loadCredentials();
    25→	if (existing) {
    26→		p.log.warn("Already logged in.");
    27→		p.outro("Run `rudel logout` first to switch accounts.");
    28→		return;
    29→	}
    30→
    31→	const state = randomBytes(16).toString("hex");
    32→
    33→	let resolveCallback: (token: string) => void;
    34→	let rejectCallback: (error: Error) => void;
    35→	const tokenPromise = new Promise<string>((resolve, reject) => {
    36→		resolveCallback = resolve;
    37→		rejectCallback = reject;
    38→	});
    39→
    40→	const server = createServer((req: IncomingMessage, res: ServerResponse) => {
    41→		const url = new URL(req.url ?? "/", `http://${req.headers.host}`);
    42→		if (url.pathname !== "/callback") {
    43→			res.writeHead(404, { "Content-Type": "text/plain" });
    44→			res.end("Not found");
    45→			return;
    46→		}
    47→
    48→		const receivedToken = url.searchParams.get("token");
    49→		const receivedState = url.searchParams.get("state");
    50→
    51→		if (receivedState !== state) {
    52→			rejectCallback(new Error("State mismatch — possible CSRF attack"));
    53→			res.writeHead(200, { "Content-Type": "text/html" });
    54→			res.end(
    55→				"<html><body><h1>Login failed</h1><p>State mismatch. Please try again.</p></body></html>",
    56→			);
    57→			return;
    58→		}
    59→
    60→		if (!receivedToken) {
    61→			rejectCallback(new Error("No token received"));
    62→			res.writeHead(200, { "Content-Type": "text/html" });
    63→			res.end(
    64→				"<html><body><h1>Login failed</h1><p>No token received.</p></body></html>",
    65→			);
    66→			return;
    67→		}
    68→
    69→		resolveCallback(receivedToken);
    70→		res.writeHead(200, { "Content-Type": "text/html" });
    71→		res.end(
    72→			"<html><body><h1>Login successful!</h1><p>You can close this tab and return to the terminal.</p></body></html>",
    73→		);
    74→	});
    75→
    76→	await new Promise<void>((resolve) => {
    77→		server.listen(0, "127.0.0.1", resolve);
    78→	});
    79→
    80→	const port = (server.address() as AddressInfo).port;
    81→	const callbackUrl = `http://127.0.0.1:${port}/callback`;
    82→	const loginUrl = `${flags.webUrl}?cli_callback=${encodeURIComponent(callbackUrl)}&state=${state}`;
    83→
    84→	p.log.info(`If the browser doesn't open, visit:\n${loginUrl}`);
    85→
    86→	// Open browser
    87→	if (!flags.noBrowser) {
    88→		if (process.platform === "win32") {
    89→			const child = spawn("cmd", ["/c", "start", "", loginUrl], {
    90→				detached: true,
    91→				stdio: "ignore",
    92→			});
    93→			child.unref();
    94→		} else {
    95→			const opener = process.platform === "darwin" ? "open" : "xdg-open";
    96→			const child = spawn(opener, [loginUrl], {
    97→				detached: true,
    98→				stdio: "ignore",
    99→			});
   100→			child.unref();
   101→		}
   102→	}
   103→
   104→	// Wait for callback with timeout
   105→	const timeout = setTimeout(() => {
   106→		rejectCallback(new Error("Login timed out after 120 seconds"));
   107→	}, CALLBACK_TIMEOUT_MS);
   108→
   109→	const spin = p.spinner();
   110→	spin.start("Waiting for browser authentication...");
   111→
   112→	let token: string;
   113→	try {
   114→		token = await tokenPromise;
   115→	} catch (error) {
   116→		clearTimeout(timeout);
   117→		server.close();
   118→		spin.stop("Authentication failed");
   119→		p.log.error(error instanceof Error ? error.message : String(error));
   120→		process.exitCode = 1;
   121→		return;
   122→	}
   123→	clearTimeout(timeout);
   124→	server.close();
   125→
   126→	spin.message("Validating token...");
   127→
   128→	// Validate token via /rpc/me
   129→	const meResponse = await fetch(`${flags.apiBase}/rpc/me`, {
   130→		method: "POST",
   131→		headers: {
   132→			"Content-Type": "application/json",
   133→			Authorization: `Bearer ${token}`,
   134→		},
   135→		body: JSON.stringify({}),
   136→	});
   137→
   138→	if (!meResponse.ok) {
   139→		spin.stop("Token validation failed");
   140→		p.log.error("Login failed: token validation failed");
   141→		process.exitCode = 1;
   142→		return;
   143→	}
   144→
   145→	const body = (await meResponse.json()) as {
   146→		json: { id: string; email: string; name: string };
   147→	};
   148→
   149→	saveCredentials(token, flags.apiBase);
   150→	spin.stop("Authenticated");
   151→	p.log.success(`Logged in as ${body.json.name} (${body.json.email})`);
   152→	p.outro("Done!");
   153→}
   154→
   155→export const loginCommand = buildCommand({
   156→	loader: async () => ({ default: runLogin }),
   157→	parameters: {
   158→		flags: {
   159→			apiBase: {
   160→				kind: "parsed",
   161→				parse: String,
   162→				brief: "API server base URL",
   163→				default: DEFAULT_API_BASE,
   164→			},
   165→			webUrl: {
   166→				kind: "parsed",
   167→				parse: String,
   168→				brief: "Web app URL for authentication",
   169→				default: DEFAULT_WEB_URL,
   170→			},
