   129→	const items: InteractiveItem[] = work.map((w) => ({
   130→		sessionId: w.session.sessionId,
   131→		label: `${w.project.displayPath}/${w.session.sessionId}`,
   132→		transcriptPath: w.session.transcriptPath,
   133→		projectPath: w.session.projectPath,
   134→		source: w.project.source,
   135→		organizationId: w.organizationId,
   136→		session: w.session,
   137→		adapter: w.adapter,
   138→		gitInfo: w.gitInfo,
   139→	}));
