   141→	const summary = await runBatchUpload({
   142→		items,
   143→		label: "Uploading sessions...",
   144→		concurrency: flags.concurrency,
   145→		upload: async (item, onRetry) => {
   146→			const request = await item.adapter.buildUploadRequest(item.session, {
   147→				tag: flags.tag,
   148→				gitInfo: item.gitInfo,
   149→				organizationId: item.organizationId,
   150→			});
