   191→): Promise<void> {
   192→	const write = (msg: string) => {
   193→		process.stdout.write(`${msg}\n`);
   194→	};
   195→	const writeError = (msg: string) => {
   196→		process.stderr.write(`${msg}\n`);
   197→	};
   198→
   199→	const credentials = loadCredentials();
   200→	if (!credentials && !flags.dryRun) {
   201→		writeError("Error: Not authenticated. Run `rudel login` first.");
   202→		process.exitCode = 1;
   203→		return;
   204→	}
