   206→	write(`Resolving session: ${session}`);
   207→	let sessionInfo: Awaited<ReturnType<typeof resolveSession>>;
   208→	try {
   209→		sessionInfo = await resolveSession(session);
   210→	} catch (error) {
   211→		writeError(
   212→			`Error: ${error instanceof Error ? error.message : String(error)}`,
   213→		);
   214→		process.exitCode = 1;
   215→		return;
   216→	}
   217→	write(`Found session at: ${sessionInfo.transcriptPath}`);
   218→
   219→	const gitInfo = await getGitInfo(sessionInfo.projectPath);
   220→	const displayName =
   221→		gitInfo.gitRemote ||
   222→		gitInfo.packageName ||
   223→		sessionInfo.projectPath.split("/").pop();
   224→	if (displayName) write(`Repository: ${displayName}`);
   225→	if (gitInfo.branch) write(`Branch: ${gitInfo.branch}`);
   226→
   227→	const organizationId =
   228→		flags.org ?? (await getProjectOrgId(sessionInfo.projectPath));
   229→	if (organizationId) write(`Organization: ${organizationId}`);
   230→
   231→	write("Building upload request...");
   232→	const sessionFile: SessionFile = {
   233→		sessionId: sessionInfo.sessionId,
   234→		transcriptPath: sessionInfo.transcriptPath,
   235→		projectPath: sessionInfo.projectPath,
   236→	};
   237→
   238→	const request = await claudeCodeAdapter.buildUploadRequest(sessionFile, {
   239→		tag: flags.tag,
   240→		gitInfo,
   241→		organizationId,
   242→	});
   243→
   244→	write(`Transcript: ${request.content.length} bytes`);
   245→	if (request.subagents && request.subagents.length > 0) {
   246→		write(`Subagents: ${request.subagents.length} file(s)`);
   247→	}
   248→
   249→	if (!flags.tag && flags.classify) {
   250→		write("Classifying session...");
   251→		const classified = await classifySession(request.content);
   252→		if (classified) {
   253→			(request as { tag?: string }).tag = classified;
   254→			write(`Classified as: ${classified}`);
   255→		}
   256→	}
   257→
   258→	if (flags.dryRun) {
   259→		const preview = {
   260→			...request,
   261→			content: `[${request.content.length} bytes]`,
   262→			subagents: request.subagents?.map((s) => ({
   263→				...s,
   264→				content: `[${s.content.length} bytes]`,
   265→			})),
   266→		};
