   269→		return;
   270→	}
   271→
   272→	write("Uploading...");
   273→	const result = await uploadSession(request, {
   274→		endpoint: flags.endpoint,
   275→		// biome-ignore lint/style/noNonNullAssertion: validated above with early return
   276→		token: credentials!.token,
   277→	});
   278→
   279→	if (result.success) {
   280→		write("Upload successful!");
   281→	} else {
   282→		writeError(`Upload failed: ${result.error}`);
   283→		process.exitCode = 1;
   284→	}
   285→}
   286→
   287→async function runRetryUpload(flags: UploadFlags): Promise<void> {
   288→	const credentials = loadCredentials();
   289→	if (!credentials) {
   290→		p.log.error("Not authenticated. Run `rudel login` first.");
   291→		process.exitCode = 1;
   292→		return;
   293→	}
   294→
   295→	p.intro("rudel upload --retry");
   296→
   297→	const failures = await loadFailedUploads();
   298→	if (failures.length === 0) {
   299→		p.outro("No failed uploads to retry.");
   300→		return;
   301→	}
   302→
   303→	p.log.info(`Found ${failures.length} failed upload(s):`);
   304→	for (const f of failures.slice(0, 10)) {
   305→		p.log.warn(`  ${f.sessionId}: ${f.error} (${f.failedAt})`);
   306→	}
   307→	if (failures.length > 10) {
   308→		p.log.warn(`  ...and ${failures.length - 10} more`);
   309→	}
   310→
   311→	const shouldRetry = await p.confirm({
   312→		message: `Retry all ${failures.length} failed upload(s)?`,
   313→		initialValue: true,
   314→	});
   315→
   316→	if (p.isCancel(shouldRetry) || !shouldRetry) {
   317→		p.cancel("Retry cancelled.");
   318→		return;
   319→	}
   320→
   321→	const endpoint = flags.endpoint;
   322→
   323→	type RetryItem = BatchUploadItem & {
   324→		failure: (typeof failures)[number];
   325→	};
   326→
   327→	const items: RetryItem[] = failures.map((f) => ({
   328→		sessionId: f.sessionId,
   329→		label: f.sessionId,
   330→		transcriptPath: f.transcriptPath,
   331→		projectPath: f.projectPath,
   332→		source: f.source,
   333→		organizationId: f.organizationId,
   334→		failure: f,
   335→	}));
   336→
   337→	const summary = await runBatchUpload({
   338→		items,
   339→		label: "Retrying uploads...",
   340→		concurrency: flags.concurrency,
   341→		upload: async (item, onRetry) => {
   342→			const adapter = item.failure.source
   343→				? getAdapter(item.failure.source)
   344→				: claudeCodeAdapter;
   345→			const sessionFile: SessionFile = {
   346→				sessionId: item.failure.sessionId,
   347→				transcriptPath: item.failure.transcriptPath,
   348→				projectPath: item.failure.projectPath,
   349→			};
   350→			const gitInfo = await getGitInfo(item.failure.projectPath);
   351→			const organizationId =
   352→				flags.org ??
   353→				item.failure.organizationId ??
   354→				(await getProjectOrgId(item.failure.projectPath));
   355→
   356→			const request = await adapter.buildUploadRequest(sessionFile, {
   357→				tag: flags.tag,
   358→				gitInfo,
   359→				organizationId,
   360→			});
   361→
   362→			return uploadSession(request, {
   363→				endpoint,
   364→				token: credentials.token,
   365→				onRetry,
   366→			});
   367→		},
   368→	});
   369→
   370→	renderBatchSummary(summary);
   371→
   372→	p.outro("Done!");
   373→
   374→	if (summary.failed > 0) {
   375→		process.exitCode = 1;
   376→	}
   377→}
   378→
   379→async function runUpload(
   380→	flags: UploadFlags,
   381→	...sessions: string[]
   382→): Promise<void> {
   383→	if (flags.retry) {
   384→		return runRetryUpload(flags);
   385→	}
   386→	if (sessions.length === 0) {
   387→		return runInteractiveUpload(flags);
   388→	}
   389→	return runSingleUpload(flags, sessions[0] as string);
   390→}
   391→
   392→export const uploadCommand = buildCommand({
   393→	loader: async () => ({ default: runUpload }),
   394→	parameters: {
   395→		positional: {
   396→			kind: "array",
   397→			parameter: {
   398→				brief: "Session ID or path to a session .jsonl file",
   399→				parse: String,
   400→				placeholder: "session",
   401→			},
   402→		},
   403→		flags: {
   404→			tag: {
   405→				kind: "enum",
   406→				values: [...SESSION_TAGS],
   407→				brief: "Session tag/category",
   408→				optional: true,
   409→			},
   410→			endpoint: {
   411→				kind: "parsed",
   412→				parse: String,
   413→				brief: "Override the upload endpoint URL",
   414→				default: DEFAULT_ENDPOINT,
   415→			},
   416→			classify: {
   417→				kind: "boolean",
   418→				brief: "Auto-classify session tag using Claude CLI",
   419→				default: false,
   420→			},
   421→			dryRun: {
   422→				kind: "boolean",
   423→				brief: "Preview what would be uploaded without sending",
   424→				default: false,
   425→			},
   426→			org: {
   427→				kind: "parsed",
   428→				parse: String,
   429→				brief: "Override the organization ID to upload to",
   430→				optional: true,
   431→			},
   432→			retry: {
   433→				kind: "boolean",
   434→				brief: "Retry previously failed uploads",
   435→				default: false,
   436→			},
   437→			concurrency: {
   438→				kind: "parsed",
   439→				parse: Number,
   440→				brief: "Max concurrent uploads",
   441→				default: "5",
   442→			},
   443→		},
   444→		aliases: {
   445→			t: "tag",
   446→			c: "classify",
   447→			n: "dryRun",
   448→			o: "org",
   449→			r: "retry",
   450→			j: "concurrency",
   451→		},
   452→	},
   453→	docs: {
   454→		brief:
   455→			"Upload session transcripts (Claude Code & Codex). No args = interactive project picker.",
   456→	},
   457→});
